def gen(rng, size):
    def num(maxlen):
        n = rng.randint(1, max(1, maxlen))
        digits = [rng.randint(0, 9) for _ in range(n)]
        if len(digits) > 1 and digits[0] == 0:
            digits[0] = rng.randint(1, 9)
        return digits
    cap = max(1, min(100, size))
    return [num(cap), num(cap)]

