class Solution:
    def addTwoNumbers(self, l1, l2):
        def to_int(node):
            n = 0
            while node:
                n = n * 10 + node.val
                node = node.next
            return n
        total = to_int(l1) + to_int(l2)
        digits = [int(c) for c in str(total)]
        new = None
        for d in reversed(digits):
            new = ListNode(d, new)
        return new

