var addTwoNumbers = function(l1, l2) {
    const s1 = [], s2 = [];
    let node = l1;
    while (node) { s1.push(node.val); node = node.next; }
    node = l2;
    while (node) { s2.push(node.val); node = node.next; }
    let carry = 0;
    let head = null;
    while (s1.length || s2.length || carry) {
        const a = s1.length ? s1.pop() : 0;
        const b = s2.length ? s2.pop() : 0;
        const total = a + b + carry;
        carry = Math.floor(total / 10);
        head = new ListNode(total % 10, head);
    }
    return head;
};
